import React, { useEffect } from "react";
import Helmet from "react-helmet";
import { graphql, navigate } from "gatsby";
import Img from "gatsby-image";
import { Layout } from "../components/layout";
import { formatDate, editOnGithub } from "../utils/global";
import siteMeta from "../../custom/siteMeta";
import { SEO } from "../components/seo";
import { PostTags } from "../components/postTags";
import { MarkdownContainer } from "../styles/container";

const ArticleTemplate = ({ pageContext, data: { markdownRemark } }) => {
  const { slug } = pageContext;
  const postNode = markdownRemark;
  const post = markdownRemark.frontmatter;
  let thumbnail;

  if (post.thumbnail) {
    thumbnail = post.thumbnail.childImageSharp.fixed;
  }

  useEffect(() => {
    if (post.status === "draft") {
      navigate("/404");
    }
  }, []);

  const date = formatDate(post.date);
  const githubLink = editOnGithub(post);

  return (
    <Layout>
      <>
        <Helmet>
          <title>{`${post.title} - ${siteMeta.siteTitle}`}</title>
        </Helmet>
        <SEO
          postPath={slug}
          postNode={postNode}
          postSEO
          robot={post.status === "draft" ? "none" : "all"}
        />
        <article>
          <header>
            {thumbnail && <Img fixed={thumbnail} />}
            <div>
              <h1>{post.title}</h1>
              <div>
                <time>{date}</time>
                <a href={githubLink} rel='noopener noreferrer' target='_blank'>
                  Edit on Github{" "}
                  <span role='img' aria-labelledby='pencil icon'>
                    ✏️
                  </span>
                </a>
              </div>
              <PostTags tags={post.tags} />
            </div>
          </header>
          <MarkdownContainer
            dangerouslySetInnerHTML={{ __html: markdownRemark.html }}
          />
        </article>
      </>
    </Layout>
  );
};

export const pageQuery = graphql`
  query BlogPostBySlug($slug: String!) {
    markdownRemark(fields: { slug: { eq: $slug } }) {
      html
      timeToRead
      excerpt
      frontmatter {
        title
        status
        thumbnail {
          childImageSharp {
            fixed(width: 150, height: 150) {
              ...GatsbyImageSharpFixed
            }
          }
        }
        slug
        date
        categories
        tags
        template
      }
      fields {
        slug
        date
      }
    }
  }
`;

export default ArticleTemplate;
